  ('disabled-0a2fc18c-moex-00214', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-111-d3ff7f6b', 'sub-disabled-0a2fc18c-04', NULL, 'single_choice', '後彎的勞動供給曲線產生的主要原因是：', '["當工資上升所產生的所得效果為正值", "當工資上升所產生的所得效果為負值", "當工資上升所產生的替代效果大於所得效果", "當工資上升所產生的所得效果大於替代效果"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:26+00:00", "source_pdf_sha1": "b9ee5641dcb5", "answer_pdf_sha1": "8e876e1802e5", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "306", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
  ('disabled-0a2fc18c-moex-00215', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-111-d3ff7f6b', 'sub-disabled-0a2fc18c-04', NULL, 'single_choice', '假設消費者為風險趨避者，下列敘述何者正確？', '["不管保險費的高低為何，此消費者一定會購買保險，以規避不確定性的 風險", "當保險的費用與預期損失相同時，此消費者一定會購買該保險", "當保險的費用大於預期損失時，此消費者一定不會購買該保險", "當保險的費用小於預期損失時，此消費者有可能不會購買該保險"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:26+00:00", "source_pdf_sha1": "b9ee5641dcb5", "answer_pdf_sha1": "8e876e1802e5", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "306", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
  ('disabled-0a2fc18c-moex-00216', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-111-d3ff7f6b', 'sub-disabled-0a2fc18c-04', NULL, 'single_choice', '消費者A的初始稟賦為（X=6,Y=4）而消費者B的初始稟賦為（X=4, Y=6）。X和Y為兩項財貨。消費者A的效用函數為 U（X,Y）=XY， 而消費者B的效用函數則為 U（X,Y）=X+Y。下列敘述何者正確？', '["目前的初始稟賦資源配置滿足柏瑞圖改善（Paretoimprovement）的定義", "目前的初始稟賦資源配置滿足柏瑞圖最適（Paretooptimum）的定義", "目前的初始稟賦資源配置不滿足柏瑞圖改善（Paretoimprovement）的定義", "目前的初始稟賦資源配置不滿足柏瑞圖最適（Paretooptimum）的定義"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:26+00:00", "source_pdf_sha1": "b9ee5641dcb5", "answer_pdf_sha1": "8e876e1802e5", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "306", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
  ('disabled-0a2fc18c-moex-00217', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-111-d3ff7f6b', 'sub-disabled-0a2fc18c-04', NULL, 'single_choice', '下列何者不是市場失靈（marketfailure）的主要原因？', '["自然獨占", "政府干預", "外部性", "公共財"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:26+00:00", "source_pdf_sha1": "b9ee5641dcb5", "answer_pdf_sha1": "8e876e1802e5", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "306", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
  ('disabled-0a2fc18c-moex-00218', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-111-d3ff7f6b', 'sub-disabled-0a2fc18c-04', NULL, 'single_choice', '下列關於貝塔係數（betacoefficient）的敘述，何者錯誤？', '["貝塔係數可用以衡量投資股票的風險程度", "貝塔係數反映著一檔股票投資報酬率相對的變化狀況與幅度", "若某一檔股票的貝塔係數小於1，代表若整體股價往上10%，該股票價 格上收幅度低於10%", "若某一檔股票的貝塔係數等於1，代表該股票的投資不具風險性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:26+00:00", "source_pdf_sha1": "b9ee5641dcb5", "answer_pdf_sha1": "8e876e1802e5", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "306", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
  ('disabled-0a2fc18c-moex-00219', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-111-d3ff7f6b', 'sub-disabled-0a2fc18c-04', NULL, 'single_choice', '在其他條件不變下，若一個封閉體系的政府降低個人所得稅率及企業的營 利事業所得稅率，則可貸資金市場的均衡實質利率會：', '["增加", "減少", "維持不變", "可能會增加、減少或維持不變"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:26+00:00", "source_pdf_sha1": "b9ee5641dcb5", "answer_pdf_sha1": "8e876e1802e5", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "306", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
  ('disabled-0a2fc18c-moex-00220', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-111-d3ff7f6b', 'sub-disabled-0a2fc18c-04', NULL, 'single_choice', '今年一農夫將一卡車羊毛以 10 元賣給紡織廠，紡織廠用這些羊毛編織了兩 件毛衣，每件價格為 50 元，且已售出其中一件，另一件則待售中。前述經 濟活動對於今年國內生產毛額（GrossDomesticProduct）貢獻為多少？', '["10", "90", "100", "110"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:26+00:00", "source_pdf_sha1": "b9ee5641dcb5", "answer_pdf_sha1": "8e876e1802e5", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "306", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
  ('disabled-0a2fc18c-moex-00221', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-111-d3ff7f6b', 'sub-disabled-0a2fc18c-04', NULL, 'single_choice', '關於吉尼係數（Ginicoefficient）與羅倫茲曲線（Lorenzcurve）的敘述，下 列何者正確？', '["吉尼係數為負數時，表示所得分配不平均", "吉尼係數的絕對值越大時，表示所得分配越平均", "羅倫茲曲線越接近對角線時，表示所得分配越平均", "描繪羅倫茲曲線的橫軸是家戶單位所得累積的百分比，縱軸是家戶單位 所得成長率的百分比"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:26+00:00", "source_pdf_sha1": "b9ee5641dcb5", "answer_pdf_sha1": "8e876e1802e5", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "306", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
  ('disabled-0a2fc18c-moex-00222', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-111-d3ff7f6b', 'sub-disabled-0a2fc18c-04', NULL, 'single_choice', '假設貨幣政策有效。根據流動性偏好理論（theoryofliquiditypreference）， 在其他條件不變下，下列何者確定會使均衡名目利率水準下降？', '["準備貨幣增加且實質GDP增加", "準備貨幣增加且實質GDP減少", "準備貨幣減少且實質GDP減少", "貨幣乘數與一般物價水準都下降"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:26+00:00", "source_pdf_sha1": "b9ee5641dcb5", "answer_pdf_sha1": "8e876e1802e5", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "306", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
  ('disabled-0a2fc18c-moex-00223', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-111-d3ff7f6b', 'sub-disabled-0a2fc18c-04', NULL, 'single_choice', '對於一個小型開放經濟體系，下列敘述何者錯誤？', '["J 曲線效果（J-curve effect）描述貨幣貶值初期會使貿易餘額（trade balance）惡化，但最終會改善貿易餘額", "在浮動匯率制度和國際資本不完全移動的小型開放經濟體系下，本國貨 幣的緊縮政策將導致本國貨幣升值", "當預期本國通貨膨脹率大於外國通貨膨脹率，本國貨幣將呈現貶值", "若中央銀行不想讓本國貨幣貶值且沒有進行沖銷（sterilization），則中 央銀行透過外匯市場買入外國貨幣，將增加貨幣基數（monetarybase）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:26+00:00", "source_pdf_sha1": "b9ee5641dcb5", "answer_pdf_sha1": "8e876e1802e5", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "306", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL)
